<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Desktop</title>
<style>
*{box-sizing:border-box;margin:0;padding:0}
body{width:100vw;height:100vh;overflow:hidden;font-family:system-ui,Ubuntu,Cantarell,sans-serif}

#desktop{
  width:100%;height:100%;
  background:radial-gradient(ellipse at 30% 60%,#1a1040 0%,#0d1b2a 45%,#0a0f1e 100%);
  position:relative;overflow:hidden;
}

/* subtle dot-grid wallpaper */
#desktop::before{
  content:'';position:absolute;inset:0;
  background-image:radial-gradient(circle,rgba(255,255,255,.07) 1px,transparent 1px);
  background-size:32px 32px;pointer-events:none;
}

/* ── TOP BAR ── */
#topbar{
  position:absolute;top:0;left:0;right:0;height:28px;
  background:rgba(15,15,20,.92);backdrop-filter:blur(12px);
  display:flex;align-items:center;padding:0 14px;
  z-index:9000;border-bottom:1px solid rgba(255,255,255,.08);
  justify-content:space-between;font-size:12px;color:#ccc;
}
#topbar-left{display:flex;gap:14px;align-items:center}
#topbar-right{display:flex;gap:10px;align-items:center}
.tb-act{color:#e95420;font-weight:700;cursor:pointer;letter-spacing:.5px}
#clock{color:#ddd}

/* ── TASKBAR / DOCK ── */
#taskbar{
  position:absolute;bottom:10px;left:50%;transform:translateX(-50%);
  background:rgba(25,25,35,.88);backdrop-filter:blur(16px);
  border:1px solid rgba(255,255,255,.12);border-radius:16px;
  display:flex;align-items:center;gap:6px;padding:6px 12px;
  z-index:9000;box-shadow:0 8px 32px rgba(0,0,0,.6);
}

.dock-btn{
  background:rgba(255,255,255,.1);border:none;color:#fff;
  padding:7px 18px;border-radius:10px;cursor:pointer;
  font-size:13px;display:flex;align-items:center;gap:7px;
  transition:background .15s,transform .15s;white-space:nowrap;
}
.dock-btn:hover{background:rgba(233,84,32,.75);transform:translateY(-2px)}
.dock-btn .di{font-size:18px;line-height:1}

/* ── WINDOWS ── */
.window{
  position:absolute;
  background:#2b2b2b;border-radius:10px;
  box-shadow:0 24px 72px rgba(0,0,0,.8),0 0 0 1px rgba(255,255,255,.1);
  display:flex;flex-direction:column;overflow:hidden;
  min-width:380px;min-height:260px;
}

.win-titlebar{
  background:linear-gradient(180deg,#3e3e3e,#383838);
  padding:9px 10px;display:flex;align-items:center;
  justify-content:space-between;cursor:move;user-select:none;
  border-bottom:1px solid rgba(0,0,0,.4);flex-shrink:0;
}
.win-title{color:#ddd;font-size:13px;font-weight:500;pointer-events:none}

.win-controls{display:flex;gap:7px;align-items:center}
.win-ctrl-btn{
  width:13px;height:13px;border-radius:50%;border:none;cursor:pointer;
  position:relative;display:flex;align-items:center;justify-content:center;
  font-size:0;transition:filter .1s;
}
.win-ctrl-btn:hover{filter:brightness(1.3)}
.win-close{background:#ff5f57}
.win-min{background:#febc2e}
.win-max{background:#28c840}
.win-close::after{content:'✕';font-size:8px;color:rgba(80,0,0,.8);opacity:0;transition:opacity .1s}
.win-close:hover::after{opacity:1}

/* ── FILES WINDOW ── */
#files-window{width:720px;height:500px;top:70px;left:90px}

.files-toolbar{
  background:#323232;padding:7px 10px;
  display:flex;align-items:center;gap:8px;
  border-bottom:1px solid rgba(0,0,0,.35);flex-shrink:0;
}
#files-up{
  background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.1);
  color:#ccc;padding:4px 11px;border-radius:5px;cursor:pointer;font-size:12px;
  transition:background .15s;
}
#files-up:hover{background:rgba(255,255,255,.2)}
#files-path{
  color:#9ab;font-size:13px;background:rgba(0,0,0,.3);
  padding:4px 10px;border-radius:5px;flex:1;min-width:0;
  overflow:hidden;text-overflow:ellipsis;white-space:nowrap;
  border:1px solid rgba(255,255,255,.07);
}

#files-list{
  flex:1;overflow-y:auto;padding:10px;
  display:flex;flex-wrap:wrap;align-content:flex-start;gap:2px;
}

.fs-item{
  display:flex;flex-direction:column;align-items:center;
  padding:10px 6px 8px;width:88px;border-radius:8px;
  cursor:default;color:#ddd;font-size:11.5px;text-align:center;
  word-break:break-word;transition:background .12s;
}
.fs-item:hover{background:rgba(255,255,255,.09)}
.fs-item.selected{background:rgba(85,130,200,.35)}
.fs-item .fi{font-size:30px;margin-bottom:5px;line-height:1;user-select:none}
.fs-item .fn{max-width:80px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;line-height:1.4}
.fs-item.folder{cursor:pointer}

/* ── NOTEPAD WINDOW ── */
#notepad-window{width:650px;height:480px;top:100px;left:220px}

.tabs-row{
  background:#313131;display:flex;align-items:stretch;
  border-bottom:1px solid rgba(0,0,0,.4);flex-shrink:0;overflow:hidden;
}
#tabs{display:flex;align-items:stretch;flex:1;overflow-x:auto;min-width:0}
#tabs::-webkit-scrollbar{height:3px}
#tabs::-webkit-scrollbar-thumb{background:rgba(255,255,255,.2)}

.tab{
  display:flex;align-items:center;gap:6px;
  padding:0 10px 0 14px;height:36px;
  color:#888;cursor:pointer;font-size:13px;
  border:none;border-right:1px solid rgba(255,255,255,.06);
  background:transparent;white-space:nowrap;
  border-bottom:2px solid transparent;transition:color .12s,background .12s;
}
.tab:hover:not(.active){background:rgba(255,255,255,.05);color:#bbb}
.tab.active{color:#f0f0f0;background:#2b2b2b;border-bottom:2px solid #e95420}
.tab-x{
  background:none;border:none;color:inherit;cursor:pointer;
  font-size:14px;padding:1px 3px;border-radius:3px;line-height:1;opacity:.6;
}
.tab-x:hover{opacity:1;background:rgba(255,255,255,.15)}

#new-tab{
  background:none;border:none;color:#777;cursor:pointer;
  font-size:20px;padding:0 14px;flex-shrink:0;
  transition:color .12s;line-height:1;
}
#new-tab:hover{color:#fff}

#editor{
  flex:1;background:#1e1e1e;color:#d4d4d4;
  border:none;padding:14px 16px;
  font-family:'Courier New',Courier,monospace;font-size:14px;
  resize:none;outline:none;line-height:1.65;
}

/* ── SCROLLBARS ── */
::-webkit-scrollbar{width:6px;height:6px}
::-webkit-scrollbar-track{background:transparent}
::-webkit-scrollbar-thumb{background:rgba(255,255,255,.18);border-radius:3px}
::-webkit-scrollbar-thumb:hover{background:rgba(255,255,255,.3)}

/* ── DESKTOP ICONS ── */
.desk-icons{position:absolute;top:36px;left:16px;display:flex;flex-direction:column;gap:6px}
.desk-icon{
  display:flex;flex-direction:column;align-items:center;gap:5px;
  padding:8px;width:72px;border-radius:8px;cursor:pointer;
  color:#eee;font-size:11px;text-align:center;transition:background .12s;
}
.desk-icon:hover{background:rgba(255,255,255,.12)}
.desk-icon .di2{font-size:32px;line-height:1}
</style>
</head>
<body>

<div id="desktop">

  <!-- top bar -->
  <div id="topbar">
    <div id="topbar-left">
      <span class="tb-act">Activities</span>
      <span style="color:#999">Firefox</span>
      <span style="color:#999">Files</span>
      <span style="color:#999">Terminal</span>
    </div>
    <div id="clock"></div>
    <div id="topbar-right">
      <span>🔊</span><span>🔋</span><span>⚙</span>
    </div>
  </div>

  <!-- desktop icons -->
  <div class="desk-icons">
    <div class="desk-icon" ondblclick="openFiles()">
      <span class="di2">🏠</span><span>Home</span>
    </div>
    <div class="desk-icon" ondblclick="openFiles()">
      <span class="di2">🗑</span><span>Trash</span>
    </div>
  </div>

  <!-- TASKBAR -->
  <div id="taskbar">
    <button class="dock-btn" id="open-files" onclick="openFiles()">
      <span class="di">📁</span>Files
    </button>
    <button class="dock-btn" id="open-notepad" onclick="openNotepad()">
      <span class="di">📝</span>Notepad
    </button>
  </div>

  <!-- FILES WINDOW -->
  <div id="files-window" class="window" style="display:none">
    <div class="win-titlebar">
      <div class="win-controls">
        <button class="win-ctrl-btn win-close" onclick="closeWin('files-window')"></button>
        <button class="win-ctrl-btn win-min"></button>
        <button class="win-ctrl-btn win-max"></button>
      </div>
      <span class="win-title">Files</span>
      <span style="width:58px"></span>
    </div>
    <div class="files-toolbar">
      <button id="files-up" onclick="filesUp()">↑ Up</button>
      <span id="files-path">/</span>
    </div>
    <div id="files-list"></div>
  </div>

  <!-- NOTEPAD WINDOW -->
  <div id="notepad-window" class="window" style="display:none">
    <div class="win-titlebar">
      <div class="win-controls">
        <button class="win-ctrl-btn win-close" onclick="closeWin('notepad-window')"></button>
        <button class="win-ctrl-btn win-min"></button>
        <button class="win-ctrl-btn win-max"></button>
      </div>
      <span class="win-title">Notepad</span>
      <span style="width:58px"></span>
    </div>
    <div class="tabs-row">
      <div id="tabs"></div>
      <button id="new-tab" title="New tab" onclick="newTab()">+</button>
    </div>
    <textarea id="editor" placeholder="Start typing…" oninput="editorInput()"></textarea>
  </div>

</div>

<script>
// ── CLOCK ────────────────────────────────────────────────
(function tick(){
  const d=new Date();
  document.getElementById('clock').textContent=
    d.toLocaleTimeString([],{hour:'2-digit',minute:'2-digit'})+
    '  '+d.toLocaleDateString([],{weekday:'short',month:'short',day:'numeric'});
  setTimeout(tick,5000);
})();

// ── Z-INDEX MANAGER ──────────────────────────────────────
let Z=100;
function bringFront(el){el.style.zIndex=++Z}

// ── DRAGGABLE WINDOWS ────────────────────────────────────
document.querySelectorAll('.window').forEach(win=>{
  let drag=false,ox=0,oy=0;
  win.querySelector('.win-titlebar').addEventListener('mousedown',e=>{
    if(e.target.closest('button'))return;
    drag=true; bringFront(win);
    ox=e.clientX-win.offsetLeft; oy=e.clientY-win.offsetTop;
    e.preventDefault();
  });
  win.addEventListener('mousedown',()=>bringFront(win));
  document.addEventListener('mousemove',e=>{
    if(!drag)return;
    const tb=document.getElementById('topbar').offsetHeight;
    win.style.left=Math.max(0,e.clientX-ox)+'px';
    win.style.top=Math.max(tb,e.clientY-oy)+'px';
  });
  document.addEventListener('mouseup',()=>{drag=false});
});

// ── WINDOW OPEN/CLOSE ────────────────────────────────────
function closeWin(id){
  document.getElementById(id).style.display='none';
}
function openFiles(){
  const w=document.getElementById('files-window');
  w.style.display='flex'; bringFront(w); renderFiles();
}
function openNotepad(){
  const w=document.getElementById('notepad-window');
  w.style.display='flex'; bringFront(w); renderTabs();
}

// ── FILESYSTEM ───────────────────────────────────────────
const FS={
  '/':                     {d:['bin','etc','home','usr','var']},
  '/bin':                  {d:['bash','cat','chmod','cp','grep','ls','mkdir','mv','pwd','rm','sh','touch']},
  '/etc':                  {d:['crontab','fstab','hostname','hosts','os-release','passwd','shadow','sudoers']},
  '/home':                 {d:['user']},
  '/home/user':            {d:['Documents','Downloads','Pictures','.bashrc','.profile','.ssh']},
  '/home/user/Documents':  {d:['notes.md','readme.txt','resume.pdf','todo.txt']},
  '/home/user/Downloads':  {d:['archive.tar.gz','setup.sh','ubuntu-22.04.iso']},
  '/home/user/Pictures':   {d:['avatar.jpg','screenshot.png','wallpaper.png']},
  '/home/user/.ssh':       {d:['authorized_keys','id_rsa','id_rsa.pub','known_hosts']},
  '/usr':                  {d:['bin','include','lib','local','share']},
  '/usr/bin':              {d:['curl','ffmpeg','git','nano','node','python3','vim','wget']},
  '/usr/include':          {d:['stdio.h','stdlib.h','string.h','unistd.h']},
  '/usr/lib':              {d:['python3','systemd','udev','x86_64-linux-gnu']},
  '/usr/local':            {d:['bin','lib','share']},
  '/usr/local/bin':        {d:[]},
  '/usr/local/lib':        {d:[]},
  '/usr/local/share':      {d:[]},
  '/usr/share':            {d:['applications','doc','fonts','man']},
  '/usr/share/applications':{d:['firefox.desktop','gedit.desktop','nautilus.desktop']},
  '/var':                  {d:['cache','lib','log','run','tmp']},
  '/var/cache':            {d:['apt','fontconfig']},
  '/var/cache/apt':        {d:['archives','pkgcache.bin']},
  '/var/lib':              {d:['apt','dpkg','systemd']},
  '/var/log':              {d:['auth.log','dpkg.log','kern.log','syslog']},
  '/var/run':              {d:['lock','udev']},
  '/var/tmp':              {d:[]},
};

const FOLDER_ICONS={
  bin:'⚙️',etc:'🔧',home:'🏠',usr:'📦',var:'📊',
  Documents:'📂',Downloads:'⬇️',Pictures:'🖼️',
  '.ssh':'🔐',log:'📋',cache:'💾',lib:'🗂️',
  share:'📤',include:'📌',local:'🏠',run:'🏃',tmp:'🗑️',
  applications:'🚀',doc:'📚',man:'📖',fonts:'🔤',
  apt:'📦',dpkg:'📦',systemd:'⚙️',udev:'🔌',
  archives:'🗃️',
};
function folderIcon(name){return FOLDER_ICONS[name]||'📁'}

const FILE_EXT_ICONS={
  sh:'📜',py:'🐍',js:'📜',ts:'📜',md:'📝',txt:'📄',
  pdf:'📕',jpg:'🖼️',png:'🖼️',iso:'💿',gz:'🗜️',
  tar:'🗜️',log:'📋',h:'📌',desktop:'🚀',
  pub:'🔑',pem:'🔑',
};
function fileIcon(name){
  const ext=name.split('.').pop().toLowerCase();
  if(name.startsWith('.'))return '⚙️';
  return FILE_EXT_ICONS[ext]||'📄';
}

let curPath='/';

function renderFiles(){
  const list=document.getElementById('files-list');
  document.getElementById('files-path').textContent=curPath;
  list.innerHTML='';
  const entry=FS[curPath];
  if(!entry)return;
  (entry.d||[]).forEach(name=>{
    const full=curPath==='/'?'/'+name:curPath+'/'+name;
    const isDir=full in FS && FS[full].d!==undefined;
    const div=document.createElement('div');
    div.className='fs-item'+(isDir?' folder':' file');
    div.innerHTML=`<span class="fi">${isDir?folderIcon(name):fileIcon(name)}</span><span class="fn">${name}</span>`;
    div.title=name;
    if(isDir){
      div.addEventListener('dblclick',()=>{curPath=full;renderFiles()});
    }
    list.appendChild(div);
  });
}

function filesUp(){
  if(curPath==='/')return;
  const parts=curPath.split('/');
  parts.pop();
  curPath=parts.join('/')||'/';
  renderFiles();
}

// ── NOTEPAD ──────────────────────────────────────────────
const LS_KEY='__desktop_notepad__';
let npTabs=[], npActive=null;

function npLoad(){
  try{
    const raw=localStorage.getItem(LS_KEY);
    if(raw){const d=JSON.parse(raw);npTabs=d.tabs||[];npActive=d.active||null;}
  }catch(_){}
  if(!npTabs.length){
    const id=uid();
    npTabs=[{id,name:'Untitled 1',text:''}];
    npActive=id;
  }
  if(!npTabs.find(t=>t.id===npActive))npActive=npTabs[0].id;
}

function npSave(){
  localStorage.setItem(LS_KEY,JSON.stringify({tabs:npTabs,active:npActive}));
}

function uid(){return 't'+Math.random().toString(36).slice(2,10)}

function renderTabs(){
  const strip=document.getElementById('tabs');
  const ed=document.getElementById('editor');
  strip.innerHTML='';
  npTabs.forEach(t=>{
    const btn=document.createElement('button');
    btn.className='tab'+(t.id===npActive?' active':'');
    btn.dataset.id=t.id;
    const label=document.createElement('span');
    label.textContent=t.name;
    const x=document.createElement('button');
    x.className='tab-x';x.textContent='×';x.title='Close';
    x.onclick=e=>{e.stopPropagation();removeTab(t.id)};
    btn.append(label,x);
    btn.onclick=()=>switchTab(t.id);
    strip.appendChild(btn);
  });
  const active=npTabs.find(t=>t.id===npActive);
  ed.value=active?active.text:'';
}

function flushEditor(){
  const active=npTabs.find(t=>t.id===npActive);
  if(active)active.text=document.getElementById('editor').value;
}

function switchTab(id){
  flushEditor();npActive=id;npSave();renderTabs();
}

function newTab(){
  flushEditor();
  const id=uid();
  npTabs.push({id,name:'Untitled '+(npTabs.length+1),text:''});
  npActive=id;npSave();renderTabs();
}

function removeTab(id){
  flushEditor();
  const idx=npTabs.findIndex(t=>t.id===id);
  npTabs.splice(idx,1);
  if(!npTabs.length){const nid=uid();npTabs=[{id:nid,name:'Untitled 1',text:''}];npActive=nid;}
  else if(npActive===id)npActive=npTabs[Math.min(idx,npTabs.length-1)].id;
  npSave();renderTabs();
}

function editorInput(){
  flushEditor();npSave();
}

// ── INIT ─────────────────────────────────────────────────
npLoad();
renderFiles();
</script>
</body>
</html>
